effect.shader:

void main() {
    highp mat3 rgb2yuv = mat3(
         0.299,     0.587,    0.114,
        -0.14713,  -0.28886,  0.436,
         0.615,    -0.51499, -0.10001
    );
    highp mat3 yuv2rgb = mat3(
        1.0,  0.0,      1.13983,
        1.0, -0.39465, -0.58060,
        1.0,  2.03211,  0.0
    );

    vec4 baseColor = texture2DCv(inputImg.texture,acScreenNorm.st);
    vec3 yuv = baseColor.rgb*rgb2yuv;

    float low = (1.0 - smoothstep(0.222, 0.444, yuv.x));
    float midLow = smoothstep(0.222, 0.444, yuv.x)*step(yuv.x, 0.555);
    float midHigh = (1.0-smoothstep(0.555, 0.777, yuv.x))*step(0.555, yuv.x) * step(yuv.x, 0.777);
    float high = smoothstep(0.555, 0.777, yuv.x);
    vec3 filter = vec3(crLow, mgLow, ybLow) * low + vec3(crMid, mgMid, ybMid)*(midLow+midHigh)+vec3(crHigh, mgHigh, ybHigh)*high;
    filter = max(min(filter, 100.0), -100.0);
    vec3 conv = (filter+vec3(100.0))/100.0;
    vec3 converted = baseColor.rgb*conv;
    vec3 convYuv = converted*rgb2yuv;
    if(fixLum) convYuv.x = yuv.x;
    vec4 outColor = vec4(convYuv*yuv2rgb, baseColor.a);
    gl_FragColor = outColor;
}
